generated_oml:
// C3: Physical sensing components
instance MotorPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor encoder providing angular position of the permanent‑magnet synchronous motor."
    DTDFVocab:producedData MotorPosDataTransmitted
]

instance GearboxPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the gearbox delivering angular position after the gearwheel gearbox."
    DTDFVocab:producedData GearboxPosDataTransmitted
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Measures motor current I_M of the drive."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

// C4: Physical-to-virtual interaction (DataTransmitted)
instance MotorPosDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorPositionEncoder
]

instance GearboxPosDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxPositionEncoder
]

instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C10: Data (raw and derived)
instance MotorAngularPositionData : DTDFVocab:Data [
    base:desc "Angular position of the motor shaft derived from MotorPosDataTransmitted."
    DTDFVocab:fromData MotorPosDataTransmitted
    DTDFVocab:inputTo MQTTEnabler, SimulinkEnabler
]

instance GearboxAngularPositionData : DTDFVocab:Data [
    base:desc "Angular position after the gearwheel gearbox derived from GearboxPosDataTransmitted."
    DTDFVocab:fromData GearboxPosDataTransmitted
    DTDFVocab:inputTo MQTTEnabler, SimulinkEnabler
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Instantaneous motor current I_M sampled from MotorCurrentDataTransmitted."
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MQTTEnabler, SimulinkEnabler
]

instance MotorAngularVelocityData : DTDFVocab:Data [
    base:desc "Motor angular velocity derived from motor position over time using VelocityCalculationModel."
    DTDFVocab:fromData MotorPosDataTransmitted
    DTDFVocab:inputTo SimulinkEnabler
]

instance ElasticityData : DTDFVocab:Data [
    base:desc "Elastic deformation estimate derived from gearbox position and motor position using VelocityCalculationModel."
    DTDFVocab:fromData MotorPosDataTransmitted, GearboxPosDataTransmitted
    DTDFVocab:inputTo SimulinkEnabler
]

instance DerivedTorqueData : DTDFVocab:Data [
    base:desc "Torque calculated from motor current and motor/gearbox models using TorqueCalculationModel."
    DTDFVocab:fromData MotorCurrentDataTransmitted, MotorPosDataTransmitted
    DTDFVocab:inputTo SimulinkEnabler
]

instance AccelerationData : DTDFVocab:Data [
    base:desc "Angular acceleration derived from motor velocity using AccelerationCalculationModel."
    DTDFVocab:fromData MotorPosDataTransmitted
    DTDFVocab:inputTo SimulinkEnabler
]

// C10: Models / Data calculation models
instance SysMLAxisModel : DTDFVocab:Model [
    base:desc "SysML block definition and internal block diagrams of the robot axis."
    DTDFVocab:inputTo SysMLEnabler
]

instance SimulinkMotorGearboxSimModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink executable model of motor, gearwheel and cycloidal gearbox (friction‑free)."
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulinkFrictionModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model incorporating static, kinetic and viscous friction for the axis."
    DTDFVocab:inputTo SimulinkEnabler
]

instance TorqueCalculationModel : DTDFVocab:Model [
    base:desc "Data calculation model that derives torque from motor current and motor/gearbox parameters."
    DTDFVocab:inputTo SimulinkEnabler
]

instance VelocityCalculationModel : DTDFVocab:Model [
    base:desc "Data calculation model that derives angular velocity and elasticity from encoder positions."
    DTDFVocab:inputTo SimulinkEnabler
]

instance AccelerationCalculationModel : DTDFVocab:Model [
    base:desc "Data calculation model that derives angular acceleration from velocity data."
    DTDFVocab:inputTo SimulinkEnabler
]

// C11: Enablers (tooling and integration)
instance SysMLEnabler : DTDFVocab:Enabler [
    base:desc "SysML toolchain used for structural and behavioral modeling of the robot axis."
    DTDFVocab:enables RealTimeFrictionIdentificationService
]

instance SimulinkEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB Simulink environment executing simulation and data calculation models."
    DTDFVocab:enables RealTimeFrictionIdentificationService, FrictionParameterUpdateService, DataVisualizationService
]

instance MQTTEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker streaming live sensor data from the physical robot to the digital shadow."
    DTDFVocab:enables DataVisualizationService
]

instance AASEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell facilitating model integration and standardized data exchange."
    DTDFVocab:enables RealTimeFrictionIdentificationService, FrictionParameterUpdateService
]

instance DashboardEnabler : DTDFVocab:Enabler [
    base:desc "Dashboard application visualizing live and simulated data for operators."
    DTDFVocab:enables DataVisualizationService
]

// C6: Services
instance RealTimeFrictionIdentificationService : DTDFVocab:Service [
    base:desc "Identifies static, kinetic and viscous friction in real time using combined white‑box and black‑box models."
    DTDFVocab:provides EnhancedMotionAccuracyInsight, PurposeDrivenTwinningInsight
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Visualizes live and simulated data streams in an operator dashboard."
    DTDFVocab:provides EnhancedMotionAccuracyInsight
]

instance FrictionParameterUpdateService : DTDFVocab:Service [
    base:desc "Generates updated friction parameters and feeds them back to the robot controller for motion‑control improvement."
    DTDFVocab:provides UpdateFrictionParametersAction, IterativeModelRefinementAction
]

// C17: Insights
instance EnhancedMotionAccuracyInsight : DTDFVocab:Insight [
    base:desc "Enhanced motion accuracy achieved by applying newly identified friction parameters to the robot controller."
]

instance PurposeDrivenTwinningInsight : DTDFVocab:Insight [
    base:desc "Purpose‑driven twinning methodology (problem identification, asset analysis, simulation, data trace definition, iterative refinement) applied to friction derivation."
]

// C17: Actions
instance UpdateFrictionParametersAction : DTDFVocab:Action [
    base:desc "Updates the robot controller with freshly identified friction parameters."
    DTDFVocab:IsAutomatic true
]

instance IterativeModelRefinementAction : DTDFVocab:Action [
    base:desc "Iteratively refines simulation and friction models based on operational feedback."
    DTDFVocab:IsAutomatic false
]

// C2: Component representing the system under study
instance AxisFirstAxis : DTDFVocab:Component [
    base:desc "First axis of the MABI MAX 100 six‑axis industrial robot, comprising a permanent‑magnet synchronous motor, a gearwheel gearbox and a cycloidal gearbox used for machining tasks."
]

// C5: Environment containing the axis component
instance RobotAxisEnvironment : DTDFVocab:Environment [
    base:contains AxisFirstAxis
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "The digital shadow is defined as having a one‑way data flow only from the physical system to the virtual model; no data or commands are sent from the virtual side back to the robot, i.e., there is no virtual‑to‑physical interaction."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous real‑time synchronization; data are captured and processed as the robot operates, enabling on‑line model updates."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A digital shadow consisting of an Asset (first axis), Sources (sensors and derived data), Processing components (simulation models and friction calculation modules), DataTraces (measured and simulated torque/velocity arrays), and a visualization dashboard, all conforming to the Digital Shadow Reference Model."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operative stage – the digital shadow is created and used during runtime of the robot to monitor and improve its motion accuracy."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Full traceability of each DataTrace to its generating Processing component and underlying models; comparison of simulated friction‑free behavior with measured data to validate and continuously update white‑box and black‑box friction models, ensuring model fidelity during runtime."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "MQTT protocol is used for transmitting sensor streams from the robot to the digital shadow; Asset Administration Shells provide standardized metadata linkage."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of the Asset Administration Shell (AAS) standard for model encapsulation and SysML as an engineering modeling standard."
]
